  1→//! Scoring engine for comparing specialist findings against benchmark ground truth.
  2→//!
  3→//! Uses location proximity and keyword overlap to match findings, then computes
  4→//! recall, precision, and weighted composite scores.
  5→
  6→use std::fmt;
  7→
  8→use forge::autoresearch::benchmarks::{Expected, ExpectedFinding, MustNotFlag};
  9→
 10→/// A finding produced by a specialist agent.
 11→#[derive(Debug, Clone, serde::Serialize, serde::Deserialize)]
 12→pub struct Finding {
 13→    pub severity: String,
 14→    pub file: String,
 15→    pub line: Option<u32>,
 16→    pub issue: String,
 17→    pub suggestion: String,
 18→}
 19→
 20→/// Composite score for a specialist's performance on benchmarks.
 21→#[derive(Debug, Clone, serde::Serialize, serde::Deserialize)]
 22→pub struct SpecialistScore {
 23→    pub recall: f64,
 24→    pub precision: f64,
 25→    pub actionability: f64,
 26→    pub composite: f64,
 27→}
 28→
 29→impl fmt::Display for SpecialistScore {
 30→    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
 31→        write!(
 32→            f,
 33→            "recall={:.1}% precision={:.1}% actionability={:.1}% composite={:.1}%",
 34→            self.recall * 100.0,
 35→            self.precision * 100.0,
 36→            self.actionability * 100.0,
 37→            self.composite * 100.0,
 38→        )
 39→    }
 40→}
 41→
