        let findings = vec![
            Finding {
                severity: "high".into(),
                file: "code.rs".into(),
                line: Some(12),
                issue: "race condition detected in query execution".into(),
                suggestion: "".into(),
            },
            Finding {
                severity: "high".into(),
                file: "code.rs".into(),
