                },
                ExpectedFinding {
                    id: "b".into(),
                    severity: "high".into(),
                    description: "missing transaction wrapper".into(),
                    location: "code.rs:30".into(),
                },
                ExpectedFinding {
                    id: "c".into(),
                    severity: "medium".into(),
