        );
    }

    #[test]
    fn test_precision_with_must_not_flag_hit() {
        let expected = Expected {
            must_find: vec![ExpectedFinding {
                id: "a".into(),
                severity: "high".into(),
                description: "race condition".into(),
                location: "code.rs:10".into(),
            }],
            must_not_flag: vec![MustNotFlag {
